     * @param {bigint} x - The integer to check.
     * @param {string} directions - The direction string.
     * @returns {boolean} True if x is a good integer, false otherwise.
     */
    const isGoodInteger = (x, directions) => {
        // 1. Format x into a 16-digit string with leading zeros
        let xStr = x.toString();
        while (xStr.length < 16) {
            xStr = "0" + xStr;
        }

        // 2. Fill the 4x4 grid (row-major order)
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));
        for (let i = 0; i < 16; i++) {
            const digit = parseInt(xStr[i]);
            const row = Math.floor(i / 4);
            const col = i % 4;
            grid[row][col] = digit;
